import { useState } from 'react';
import { ChevronDown } from 'lucide-react';

export function AccordionFaq() {
  const [openIndex, setOpenIndex] = useState(null);

  const faqs = [
    {
      q: "What is OpenBlocks?",
      a: "OpenBlocks is a local-first, Rust-native Model Context Protocol (MCP) server that provides a structured registry of components and layout templates for AI coding agents."
    },
    {
      q: "How does it save context tokens?",
      a: "Instead of asking an LLM to generate code from scratch, agents search and retrieve existing components by UUID, passing only modular IDs until rendering, which prevents context window bloat."
    },
    {
      q: "Which clients are supported?",
      a: "OpenBlocks exposes standard stdio transport tools, which makes it compatible with any MCP client including Claude Desktop, Cursor, Cline, Roo Code, and Windsurf."
    }
  ];

  const toggle = (idx) => {
    setOpenIndex(openIndex === idx ? null : idx);
  };

  return (
    <div className="mx-auto w-full max-w-2xl px-4 py-8">
      <h2 className="text-2xl font-bold tracking-tight text-center text-foreground mb-6">
        Frequently Asked Questions
      </h2>
      <div className="divide-y divide-border border-y border-border">
        {faqs.map((faq, idx) => {
          const isOpen = openIndex === idx;
          return (
            <div key={idx} className="py-4">
              <button 
                onClick={() => toggle(idx)}
                className="flex w-full items-center justify-between text-left font-medium text-foreground transition-colors hover:text-primary"
              >
                <span>{faq.q}</span>
                <ChevronDown className={`h-4 w-4 shrink-0 text-muted-foreground transition-transform duration-200 ${isOpen ? 'rotate-180' : ''}`} />
              </button>
              <div className={`grid transition-all duration-200 ease-in-out ${isOpen ? 'grid-rows-[1fr] opacity-100 mt-2' : 'grid-rows-[0fr] opacity-0'}`}>
                <div className="overflow-hidden text-sm text-muted-foreground leading-relaxed">
                  {faq.a}
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
